onClick:
{{
(async () => {
  const action = PicklistRules.listCode() === "diet_tag"
    ? "delete"
    : radPLReplaceDeleteAction.selectedOptionValue;

  const replaceToId = PicklistRules.listCode() === "diet_tag"
    ? null
    : selPLReplaceWith.selectedOptionValue;

  if (action === "replace" && !replaceToId) {
    showAlert("Select a replacement item first.", "warning");
    return;
  }

  await getHelperIngredientImpactCount.run();
  await getHelperRecipeImpactCount.run();

  if (
    action === "delete" &&
    PicklistRules.isCategory() &&
    PicklistRules.totalImpactCount() > 0 &&
    !replaceToId
  ) {
    showAlert("This category is currently being used. Select a replacement before deleting.", "warning");
    return;
  }

  await storeValue("plReplaceAction", action === "replace" ? "Replace" : "Delete");
  await storeValue("plReplaceToId", replaceToId || null);

  if (
    action === "delete" &&
    !replaceToId &&
    PicklistRules.totalImpactCount() > 0
  ) {
    showModal("mdPLReplaceConfirm");
    return;
  }

  await PicklistActions.confirmReplaceDelete();
})()
}}
